module RefModule(
    X ,
    A1,
    A2,
    B1
);output X ;
    input  A1;
    input  A2;
    input  B1;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

  wire temp1_(A1 & B1) | (A2 & B1) = (A1 & B1) | (A2 & B1);
  wire temp2_(!A1 & !A2) = (!A1 & !A2);
  assign X = temp1_(A1 & B1) | (A2 & B1) | temp2_(!A1 & !A2);

endmodule
